const top = $input.first().json || {};
const body = top.body || top;
const resource = (body && body.resource) || top.resource || {};
const eventData = (body && body.eventData) || top.eventData || {};
const dataset_id = resource.defaultDatasetId || body.defaultDatasetId || top.defaultDatasetId || '';
const run_id = resource.id || body.run_id || eventData.actorRunId || '';
const task_id = eventData.actorTaskId || body.task_id || top['X-Apify-Task-Id'] || '';
const tenant_id = body.tenant_id || top.tenant_id || '23610954-5fd0-482f-8eb0-11edce1f5c58';
const feature_id = body.feature_id || top.feature_id || '';
return [{ json: { dataset_id, run_id, task_id, tenant_id, feature_id, body, resource, eventData } }];

// FEAT-007 SERP Tier1 classifier
const items = $input.all();
const ev = $('Webhook').item.json.body || {};
const headers = ev.headers || {};
const tenantId = headers['x-tenant-id'] || '23610954-5fd0-482f-8eb0-11edce1f5c58';
const taskId = ev.eventData?.actorTaskId || null;
const runId = ev.resource?.id || null;
const datasetId = ev.resource?.defaultDatasetId || null;

const OWNED = ['creditaccessgrameen.in', 'grameenkoota.in', 'creditaccess.com', 'creditaccesslife.in'];
const WHITELIST = ['icra.in', 'screener.in', 'bseindia.com', 'nseindia.com', 'moneycontrol.com',
                   'cleartax.in', 'arihantcapital.com', 'indiaadvantage.co.in', 'bajajfinserv.in',
                   'shriramfinance.in'];

function classify(url, title, desc, query) {
  const u = (url || '').toLowerCase();
  const blob = ((url || '') + ' ' + (title || '') + ' ' + (desc || '')).toLowerCase();
  const q = (query || '').toLowerCase();
  if (u.includes('t.me/') || u.includes('telegram.me/'))
    return { kind: 'username_squat', severity: 'Moderate', confidence: 0.55 };
  if (q.includes('login') || q.includes('verify'))
    return { kind: 'phishing', severity: 'Substantial', confidence: 0.65 };
  if (q.includes('giveaway') || blob.includes('giveaway') || blob.includes('prize'))
    return { kind: 'fraud', severity: 'Moderate', confidence: 0.5 };
  if (u.includes('play.google.com') || u.includes('apkpure'))
    return { kind: 'fraud', severity: 'Substantial', confidence: 0.6 };
  if (u.includes('instagram.com') || u.includes('facebook.com') || u.includes('twitter.com') || u.includes('x.com'))
    return { kind: 'brand_impersonation', severity: 'Moderate', confidence: 0.45 };
  return { kind: 'fraud', severity: 'Low', confidence: 0.4 };
}

const rows = [];
for (const itm of items) {
  const j = itm.json || {};
  const queryArr = Array.isArray(j) ? j : [j];
  for (const qi of queryArr) {
    const term = qi?.searchQuery?.term || '';
    const organic = qi?.organicResults || [];
    for (let i = 0; i < organic.length; i++) {
      const r = organic[i];
      const url = (r.url || '').toLowerCase();
      if (!url) continue;
      if (OWNED.some(d => url.includes(d))) continue;
      if (WHITELIST.some(h => url.includes(h))) continue;
      const c = classify(url, r.title, r.description, term);
      rows.push({
        tenant_id: tenantId,
        apify_task_id: taskId,
        apify_run_id: runId,
        apify_dataset_id: datasetId,
        feature_id: 'FEAT-007',
        source: 'apify:google-search',
        kind: c.kind,
        fraud_pattern: c.kind === 'phishing' ? 'phishing' :
                       c.kind === 'fraud' ? 'recovery_scam' :
                       c.kind === 'username_squat' || c.kind === 'brand_impersonation' ? 'impersonation' : null,
        severity: c.severity,
        confidence: c.confidence,
        item_id: r.url,
        url_or_value: r.url,
        evidence: { title: r.title, description: (r.description || '').slice(0, 250), query: term, position: i + 1 },
        language_detected: qi.searchQuery?.languageCode || null,
        matched_keywords: term ? [term] : [],
        ai_filtered: false,
        ai_reason: `Heuristic match (${c.kind}) on ${term ? 'query: ' + term : 'organic result'}`,
        recommended_action: 'monitor',
      });
    }
  }
}
return [{ json: { rows, count: rows.length } }];
